import{_ as n,C as o,o as r,c as t,a2 as s,E as i}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Permisos","description":"","frontmatter":{},"headers":[],"relativePath":"es/features/permissions.md","filePath":"es/features/permissions.md"}'),l={name:"es/features/permissions.md"};function c(p,e,d,h,m,u){const a=o("Screenshot");return r(),t("div",null,[e[0]||(e[0]=s('<h1 id="permisos" tabindex="-1">Permisos <a class="header-anchor" href="#permisos" aria-label="Permalink to &quot;Permisos&quot;">​</a></h1><p>El panel de Permisos es una interfaz CRUD completa sobre el modelo <code>Permission</code> de Spatie. Clearance nunca introduce su propia tabla de permisos - cada permiso que creas aquí es un permiso de Spatie normal, utilizable en cualquier lugar donde se use la API de Spatie (<code>$user-&gt;can()</code>, <code>Gate::allows()</code>, políticas, <code>@can</code>).</p><h2 id="que-hace-el-panel" tabindex="-1">Qué hace el panel <a class="header-anchor" href="#que-hace-el-panel" aria-label="Permalink to &quot;Qué hace el panel&quot;">​</a></h2><ul><li><strong>Crear</strong> - añade un nuevo permiso, validado contra la <a href="#permission-naming-convention">convención de nomenclatura</a> (a menos que esté desactivada) y limitado a un guard.</li><li><strong>Editar</strong> - renombra un permiso o cambia su guard.</li><li><strong>Eliminar</strong> - elimina un permiso y sus asignaciones de rol/usuario (comportamiento de cascada estándar de Spatie).</li></ul>',4)),i(a,{src:"/screenshots/permissions-page.png",alt:"Panel de Permisos de Clearance listando permisos agrupados por prefijo de nomenclatura",caption:"El panel de Permisos lista cada permiso de Spatie, agrupado por prefijo de nomenclatura."}),i(a,{src:"/screenshots/permission-form-modal.png",alt:"Formulario de creación/edición de permisos con validación de la convención de nomenclatura",caption:"El formulario de permisos valida la convención de nomenclatura group-action antes de guardar."}),e[1]||(e[1]=s(`<h2 id="convencion-de-nomenclatura-de-permisos" tabindex="-1">Convención de Nomenclatura de Permisos <a class="header-anchor" href="#convencion-de-nomenclatura-de-permisos" aria-label="Permalink to &quot;Convención de Nomenclatura de Permisos&quot;">​</a></h2><p>Los permisos deben seguir el formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>El prefijo de grupo (<code>orders</code> en <code>orders-create</code>) es lo que el <a href="/clearance-docs/es/features/dashboard.html">Panel de Control</a> usa para contar los grupos de permisos distintos.</p><div class="tip custom-block"><p class="custom-block-title">Desactivar la validación</p><p>Algunos equipos migran desde un esquema de nomenclatura diferente. Desactiva la comprobación por entorno:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="control-de-acceso" tabindex="-1">Control de acceso <a class="header-anchor" href="#control-de-acceso" aria-label="Permalink to &quot;Control de acceso&quot;">​</a></h2><p>El acceso de lectura al panel (ver la lista de permisos) requiere <code>clearance-access</code>. Crear, editar o eliminar un permiso requiere adicionalmente <code>clearance-permissions-write</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Los permisos <code>clearance-*</code> están reservados</p><p>Los propios permisos <code>clearance-*</code> (<code>clearance-access</code>, <code>clearance-permissions-write</code>, etc.) no pueden crearse, renombrarse ni eliminarse a través de este panel - ni siquiera por un actor <code>super_admin</code>. Se gestionan exclusivamente mediante el propio flujo de instalación del paquete. Consulta <a href="/clearance-docs/es/features/super-admin.html#reserved-clearance-permissions">Super Admin</a>.</p></div><h2 id="ruta-y-componente-incorporado" tabindex="-1">Ruta y componente incorporado <a class="header-anchor" href="#ruta-y-componente-incorporado" aria-label="Permalink to &quot;Ruta y componente incorporado&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nombre de ruta</th><th>Descripción</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>Permission CRUD with group-prefix naming validation</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/features/roles.html">Roles</a> - asigna permisos a un rol, limitado por guard.</li><li><a href="/clearance-docs/es/features/super-admin.html">Super Admin</a> - la tabla completa de permisos de escritura granulares.</li><li><a href="/clearance-docs/es/guide/configuration.html">Referencia de configuración</a> - <code>enforce_naming_convention</code>, <code>naming_separator</code>.</li></ul>`,14))])}const b=n(l,[["render",c]]);export{k as __pageData,b as default};
